starterCss:
/* Create a grid layout:
   - 2 columns: 200px sidebar + 1fr main
   - Header and footer span both columns
   - 10px gap between all areas */
.layout > * {
  padding: 16px;
  background-color: #e0e0e0;
}

referenceSolutions:
.layout {
  display: grid;
  grid-template-columns: 200px 1fr;
  gap: 10px;
}
.layout > * {
  padding: 16px;
  background-color: #e0e0e0;
}
.header {
  grid-column: 1 / -1;
}
.footer {
  grid-column: 1 / -1;
}

.layout {
  display: grid;
  grid-template-columns: 200px 1fr;
  grid-template-areas:
    "header header"
    "sidebar main"
    "footer footer";
  gap: 10px;
}
.layout > * {
  padding: 16px;
  background-color: #e0e0e0;
}
.header { grid-area: header; }
.sidebar { grid-area: sidebar; }
.main { grid-area: main; }
.footer { grid-area: footer; }
